sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // Get the currently logged-in user's sys_id
    var user = gs.getUser();

    // Query the sys_user table for this user
    if (user) {
        // If found, return the user's profile information
        response.setStatus(200);
        response.setBody({
			id: user.getID(),
			name: user.getName(),
            display_name: user.getDisplayName(),
            first_name: user.getFirstName(),
            last_name: user.getLastName(),
            email: user.getEmail(),
			roles: user.getRoles(),
			user_roles: user.getUserRoles()
        });
    } else {
        // If not found, return an error
        response.setStatus(404);
        response.setBody({
            error: 'User not found'
        });
    }

})(request, response);
